#include <stdio.h>
#include <string.h>

struct Student {
    char name[50];
    int rollNo;
    float marks;
};

// Function prototypes
void acceptStudent(struct Student *s);
void displayStudent(struct Student s);
float calculateAverage(struct Student students[], int n);

int main() {
    int n;
    printf("Enter number of students: ");
    scanf("%d", &n);

    struct Student students[100];

    // Accept student data
    for (int i = 0; i < n; i++) {
        acceptStudent(&students[i]);
    }

    // Display all students
    printf("\nStudent Details:\n");
    for (int i = 0; i < n; i++) {
        displayStudent(students[i]);
    }

    // Calculate and display average
    float avg = calculateAverage(students, n);
    printf("\nAverage Marks: %.2f\n", avg);

    return 0;
}

void acceptStudent(struct Student *s) {
    printf("\nEnter name: ");
    scanf("%s", s->name);
    printf("Enter roll number: ");
    scanf("%d", &s->rollNo);
    printf("Enter marks: ");
    scanf("%f", &s->marks);
}

void displayStudent(struct Student s) {
    printf("Name: %s, Roll: %d, Marks: %.2f\n", 
           s.name, s.rollNo, s.marks);
}

float calculateAverage(struct Student students[], int n) {
    float sum = 0;
    for (int i = 0; i < n; i++) {
        sum += students[i].marks;
    }
    return sum / n;
}

#include <iostream>
#include <string>
using namespace std;

class Student {
private:  // Data hiding - private by default
    string name;
    int rollNo;
    float marks;

public:  // Public interface
    // Constructor
    Student() {
        name = "";
        rollNo = 0;
        marks = 0.0;
    }

    // Parameterized constructor
    Student(string n, int r, float m) {
        name = n;
        rollNo = r;
        marks = m;
    }

    // Setter methods (mutators)
    void setName(string n) { name = n; }
    void setRollNo(int r) { rollNo = r; }
    void setMarks(float m) { 
        if (m >= 0 && m <= 100) 
            marks = m; 
    }

    // Getter methods (accessors)
    string getName() const { return name; }
    int getRollNo() const { return rollNo; }
    float getMarks() const { return marks; }

    // Member function
    void display() const {
        cout << "Name: " << name 
             << ", Roll: " << rollNo 
             << ", Marks: " << marks << endl;
    }

    // Destructor
    ~Student() {
        // Cleanup code if needed
    }
};

int main() {
    // Create objects
    Student s1("Rahul", 101, 85.5);
    Student s2;

    s2.setName("Priya");
    s2.setRollNo(102);
    s2.setMarks(92.0);

    // Display using member function
    s1.display();
    s2.display();

    return 0;
}

#include <iostream>
using namespace std;

// Base class
class Shape {
protected:
    string color;

public:
    Shape(string c = "white") : color(c) {}

    // Pure virtual function - makes Shape abstract
    virtual double area() const = 0;

    // Virtual function for polymorphism
    virtual void display() const {
        cout << "Color: " << color << endl;
    }

    virtual ~Shape() {}
};

// Derived class 1: Circle
class Circle : public Shape {
private:
    double radius;

public:
    Circle(double r, string c = "red") : Shape(c), radius(r) {}

    // Override area()
    double area() const override {
        return 3.14159 * radius * radius;
    }

    void display() const override {
        cout << "Circle - ";
        Shape::display();
        cout << "Radius: " << radius 
             << ", Area: " << area() << endl;
    }
};

// Derived class 2: Rectangle
class Rectangle : public Shape {
private:
    double length, width;

public:
    Rectangle(double l, double w, string c = "blue") 
        : Shape(c), length(l), width(w) {}

    double area() const override {
        return length * width;
    }

    void display() const override {
        cout << "Rectangle - ";
        Shape::display();
        cout << "Length: " << length 
             << ", Width: " << width
             << ", Area: " << area() << endl;
    }
};

int main() {
    // Create objects of derived classes
    Circle c(5.0);
    Rectangle r(10.0, 5.0);

    // Direct object calls
    cout << "=== Direct Calls ===" << endl;
    c.display();
    r.display();

    // Polymorphism through base class pointer
    cout << "\n=== Polymorphic Calls ===" << endl;
    Shape *shapes[2];
    shapes[0] = &c;
    shapes[1] = &r;

    for (int i = 0; i < 2; i++) {
        shapes[i]->display();  // Calls appropriate derived version
    }

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

// Base class 1
class Person {
protected:
    string name;
    int age;

public:
    Person(string n = "", int a = 0) : name(n), age(a) {}

    void displayPerson() const {
        cout << "Name: " << name 
             << ", Age: " << age << endl;
    }
};

// Base class 2
class Employee {
protected:
    int empId;
    double salary;

public:
    Employee(int id = 0, double sal = 0.0) 
        : empId(id), salary(sal) {}

    void displayEmployee() const {
        cout << "Emp ID: " << empId 
             << ", Salary: " << salary << endl;
    }
};

// Derived class using multiple inheritance
class Manager : public Person, public Employee {
private:
    string department;

public:
    Manager(string n, int a, int id, double sal, string dept)
        : Person(n, a), Employee(id, sal), department(dept) {}

    void display() const {
        cout << "\n=== Manager Details ===" << endl;
        displayPerson();
        displayEmployee();
        cout << "Department: " << department << endl;
    }
};

int main() {
    // Create Manager object
    Manager m("Dr. Sharma", 45, 1001, 75000.0, "Computer Science");

    m.display();

    return 0;
}
